window.QUIZ_FRAGMENT_HTML = "<h1>📝 BPC_SOS_2026_polsemestralka</h1>\n\n<div class=\"section\" id=\"sec_1\" data-section=\"1\">\n    <div class=\"section-title\">1. Zápočtový test SOS 2021</div>\n\n    <div class=\"question\" id=\"q1_1\" data-answer=\"c\">\n        <div class=\"question-label\">1. Příkazy <code>cd /home/uzivatel/temp/; ./skript.sh</code> spustí skript.sh:</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_1\" value=\"a\" /><span>Z adresáře /home</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_1\" value=\"b\" /><span>Z adresáře /bin</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_1\" value=\"c\" /><span>Z aktuálního adresáře</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_1\" value=\"d\" /><span>Z adresáře /root</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_1-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_2\" data-answer=\"a\">\n        <div class=\"question-label\">2. Pokud chceme práva u adresáře nastavit tak, aby soubory vytvořené v tomto adresáři získaly skupinové vlastnictví podle adresáře, a dále pro vlastníka adresáře plná práva; žádná práva pro skupinu vlastníka adresáře a ostatní uživatele, tak použijeme příkaz chmod s těmito parametry:</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_2\" value=\"a\" /><span>2700</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_2\" value=\"b\" /><span>700</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_2\" value=\"c\" /><span>0077</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_2\" value=\"d\" /><span>2007</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_2-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_3\" data-answer=\"b\">\n        <div class=\"question-label\">3. Co bude provádět konstrukce <code>***** ~/copy.sh >> ~/zaloha.txt</code>, kterou předáte programu crontab?</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_3\" value=\"a\" /><span>Program crontab NEbude provádět nic, protože znak \"~\" NElze v tomto zápisu použít.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_3\" value=\"b\" /><span>Do souboru zaloha.txt se bude přidávat textový výstup skriptu copy.sh.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_3\" value=\"c\" /><span>Obsah skriptu copy.sh bude každou minutu zkopírován do souboru zaloha.txt. Původní data v souboru zaloha.txt budou přepsána.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_3\" value=\"d\" /><span>Skript copy.sh se bude spouštět jednou za rok.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_3-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_4\" data-answer=\"c\">\n        <div class=\"question-label\">4. U adresáře je uvedeno oprávnění označené jako x. Co toto oprávnění značí?</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_4\" value=\"a\" /><span>Oprávnění k přesunu.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_4\" value=\"b\" /><span>Oprávnění ke spuštění.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_4\" value=\"c\" /><span>Oprávnění ke vstupu.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_4\" value=\"d\" /><span>Oprávnění k mazání.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_4-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_5\" data-answer=\"a\">\n        <div class=\"question-label\">5. Co značí u nastavení oprávnění souboru hodnota 664?</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_5\" value=\"a\" /><span>Všichni uživatelé mohou soubor číst, vlastník souboru a skupina vlastníka souboru mohou do souboru zapisovat.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_5\" value=\"b\" /><span>Vlastník souboru a skupina vlastníka souboru může soubor spustit. Ostatní uživatelé mohou do souboru pouze zapisovat.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_5\" value=\"c\" /><span>Vlastník souboru a skupina vlastníka souboru může soubor spustit. Ostatní uživatelé mohou provádět vše mimo spouštění.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_5\" value=\"d\" /><span>Všichni uživatelé mohou soubor číst, vlastník souboru a skupina vlastníka souboru může soubor spustit.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_5-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_6\" data-answer=\"b\">\n        <div class=\"question-label\">6. Jaké informace značí výpis <code>lrwxrwxrwx</code> u položky ve výpisu obsahu adresáře?</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_6\" value=\"a\" /><span>Nastala chyba v souborovém systému.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_6\" value=\"b\" /><span>Práva jsou ignorována.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_6\" value=\"c\" /><span>Právo čtení, zápisu a spouštění má vlastník, skupina vlastníka a ostatní uživatelé.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_6\" value=\"d\" /><span>Jedná se o adresář uživatele root.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_6-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_7\" data-answer=\"a\">\n        <div class=\"question-label\">7. Jaký efekt bude mít sekvence příkazů <code>more hesla.txt; who am i; echo $PATH</code>?</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_7\" value=\"a\" /><span>Příkazy budou provedeny postupně zleva doprava: nejdříve se provede výpis obsahu souboru hesla.txt, pak výpis informací o aktuálním uživateli, nakonec výpis systémové proměnné PATH.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_7\" value=\"b\" /><span>První dva příkazy budou spuštěny najednou...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_7\" value=\"c\" /><span>Příkazy budou zřetězeny...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_7\" value=\"d\" /><span>Příkazy budou provedeny postupně zprava doleva...</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_7-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_8\" data-answer=\"a\">\n        <div class=\"question-label\">8. Ve cvičení jste si příkazem gpg pro účely bezpečné komunikace generovali:</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_8\" value=\"a\" /><span>Veřejný a privátní klíč.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_8\" value=\"b\" /><span>Pouze tajný klíč.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_8\" value=\"c\" /><span>Symetrický klíč.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_8\" value=\"d\" /><span>Pouze veřejný klíč.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_8-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_9\" data-answer=\"a\">\n        <div class=\"question-label\">9. Jaké informace značí výpis <code>lrwxrwxrwx</code> u položky ve výpisu obsahu adresáře? (symbolický odkaz)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_9\" value=\"a\" /><span>Pouze to, že se jedná o symbolický odkaz.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_9\" value=\"b\" /><span>Pouze to, že se jedná o adresář.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_9\" value=\"c\" /><span>Vlastníkem položky s těmito právy je užívatel root.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_9\" value=\"d\" /><span>Vlastníkem položky s těmito právy je aktuální užívatel.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_9-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_10\" data-answer=\"a\">\n        <div class=\"question-label\">10. Administrátor systému, ve kterém se nepoužívala stíněná hesla, se rozhodl přejít na použití stínových hesel a uložit je v souboru /etc/shadow. Vyberte správnou akci pro zavedení souboru.</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_10\" value=\"a\" /><span>chmod 400 /etc/shadow</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_10\" value=\"b\" /><span>chmod 004 /etc/shadow</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_10\" value=\"c\" /><span>chmod 444 /etc/shadow</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_10\" value=\"d\" /><span>chmod 006 /etc/shadow</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_10-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_11\" data-answer=\"b\">\n        <div class=\"question-label\">11. Co můžete říci o těchto dvou různých zápisech IP adresy z pohledu masky sítě? 1) 192.168.1.0 255.255.255.0; 2) 192.168.1.0/24</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_11\" value=\"a\" /><span>Oba dva zápisy jsou chybné.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_11\" value=\"b\" /><span>Uvedená maska sítě je v obou případech stejná.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_11\" value=\"c\" /><span>Případ 2) NEvyjadřuje zápis IP adresy a masky sítě, případ 1) ano.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_11\" value=\"d\" /><span>Případ 1) NEvyjadřuje správný zápis IP adresy a masky sítě, případ 2) ano.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_11-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_12\" data-answer=\"a\">\n        <div class=\"question-label\">12. Jak je možné zajistit neprivilegovanému uživateli možnost spouštět určité příkazy s právy administrátora (root)?</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_12\" value=\"a\" /><span>Lze použít nástroj sudo ve formátu: sudo příkaz. V souboru /etc/sudoers jsou pak uloženy příkazy...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_12\" value=\"b\" /><span>Vytvořením symbolického odkazu...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_12\" value=\"c\" /><span>Vytvořením pevného odkazu...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_12\" value=\"d\" /><span>Pomocí zamezení používání stínových hesel...</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_12-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_13\" data-answer=\"c\">\n        <div class=\"question-label\">13. U souboru máme nastaveno toto oprávnění, vlastník: rwx, skupina: rw-, ostatní: r-. Jaká bude číselná hodnota tohoto oprávnění?</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_13\" value=\"a\" /><span>676</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_13\" value=\"b\" /><span>670</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_13\" value=\"c\" /><span>764</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_13\" value=\"d\" /><span>766</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_13-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_14\" data-answer=\"a\">\n        <div class=\"question-label\">14. Pokud chceme u adresáře nastavit pro vlastníka a skupinu vlastníka adresáře právo vstoupit a zobrazit soubory v adresáři; žádná práva pro ostatní uživatele, tak použijeme příkaz chmod s těmito parametry:</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_14\" value=\"a\" /><span>550</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_14\" value=\"b\" /><span>660</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_14\" value=\"c\" /><span>442</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_14\" value=\"d\" /><span>551</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_14-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_15\" data-answer=\"d\">\n        <div class=\"question-label\">15. V jakých sítích je vhodné použití programu Telnet?</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_15\" value=\"a\" /><span>Pro svou grafickou náročnost...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_15\" value=\"b\" /><span>Pro svou jednoduchost... ve veřejné síti Internet.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_15\" value=\"c\" /><span>Pro svou jednoduchost... ve starších sítích...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_15\" value=\"d\" /><span>Pouze v privátních sítích (např. laboratoř), bez napojení na vnější síť.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_15-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_16\" data-answer=\"c\">\n        <div class=\"question-label\">16. Výraz ve skriptu příkazového interpretu <code>#!/bin/bash</code> značí:</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_16\" value=\"a\" /><span>Provedení příkazu /bin...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_16\" value=\"b\" /><span>Provedení příkazu /bin/bash na pozadí...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_16\" value=\"c\" /><span>Deklaraci programu, pomocí kterého se bude skript interpretovat.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_16\" value=\"d\" /><span>Provedení příkazu bash pod uživatelem root.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_16-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_17\" data-answer=\"c\">\n        <div class=\"question-label\">17. Určete, které použití znaku roury a znaků přesměrování <code><></code> je správné k tomu, abychom vypsali obsah souboru /data/seznam tak, aby byly vypsány pouze řádky s výskytem slova root. Řádky mají být seřazeny abecedně v souboru /data/serazeno.</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_17\" value=\"a\" /><span><code>cat | grep | sort </data/seznam root > /data/serazeno</code></span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_17\" value=\"b\" /><span><code>sort | grep | sort </data/serazeno >/data/seznam root</code></span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_17\" value=\"c\" /><span><code>cat /data/seznam | grep root | sort >/data/serazeno</code></span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_17\" value=\"d\" /><span><code>cat | grep | sort</data/serazeno root >/data/seznam</code></span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_17-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_18\" data-answer=\"c\">\n        <div class=\"question-label\">18. Jaké jsou důležité programy pro zobrazení konfigurace sítě?</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_18\" value=\"a\" /><span>bash a sudo</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_18\" value=\"b\" /><span>config a chmod</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_18\" value=\"c\" /><span>ifconfig a ip</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_18\" value=\"d\" /><span>chmod a touch</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_18-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_19\" data-answer=\"b\">\n        <div class=\"question-label\">19. Příkazy <code>cd /home/uzivatel/temp/; ./skript.sh</code> spustí skript.sh:</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_19\" value=\"a\" /><span>Z adresáře /bin</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_19\" value=\"b\" /><span>Z aktuálního adresáře.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_19\" value=\"c\" /><span>Z adresáře /home</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_19\" value=\"d\" /><span>Z adresáře /root</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_19-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_20\" data-answer=\"a\">\n        <div class=\"question-label\">20. K čemu je dobré zobrazení přehledu síťových spojení na síťovém zařízení?</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_20\" value=\"a\" /><span>Pro získání přehledu otevřených portů a stavu jednotlivých spojení.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_20\" value=\"b\" /><span>Pro zjištění trasy ke vzdálené stanici...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_20\" value=\"c\" /><span>Pro zjištění verze operačních systému...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_20\" value=\"d\" /><span>Pro zjištění stavu směrovací tabulky...</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_20-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_21\" data-answer=\"b\">\n        <div class=\"question-label\">21. Aktuální adresář se do proměnné PATH nezahrnuje z důvodu:</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_21\" value=\"a\" /><span>Spustitelné soubory nebývají umístěny mimo adresář /bin.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_21\" value=\"b\" /><span>Bezpečnosti.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_21\" value=\"c\" /><span>V proměnné PATH může být jenom adresář /bin.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_21\" value=\"d\" /><span>Spustitelné soubory z aktuálního adresáře se spouštějí automaticky...</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_21-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_22\" data-answer=\"d\">\n        <div class=\"question-label\">22. Jakým způsobem se spouští skript v příkazovém interpretu?</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_22\" value=\"a\" /><span>Pomocí kompilace do binárního kódu pomocí příkazu gec.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_22\" value=\"b\" /><span>Pomocí vytvoření symbolického odkazu...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_22\" value=\"c\" /><span>Pomocí vytvoření pevného odkazu...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_22\" value=\"d\" /><span>Pomocí příkazu <code>sh <název skriptu></code> nebo <code>./<název skriptu></code>.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_22-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_23\" data-answer=\"d\">\n        <div class=\"question-label\">23. Hlášení \"module licence XY taints kernel\" v systémovém logu může znamenat, že:</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_23\" value=\"a\" /><span>Do jádra byl vložen modul s neoriginálním ovladačem.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_23\" value=\"b\" /><span>Nastala chyba v modulu jádra...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_23\" value=\"c\" /><span>Jádro bylo infikováno virem nebo malwarem s licencí.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_23\" value=\"d\" /><span>Do jádra byl zaveden modul bez zadané licence.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_23-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_24\" data-answer=\"d\">\n        <div class=\"question-label\">24. Co je to příkazový interpret (shell)?</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_24\" value=\"a\" /><span>Program, který je součástí jádra operačního systému.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_24\" value=\"b\" /><span>Hardware, který je připojen k datové sběrnici...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_24\" value=\"c\" /><span>Hardware, který slouží pro ovládání počítače hlasem.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_24\" value=\"d\" /><span>Program, který NEní součástí jádra operačního systému. Je to prostředník mezi uživatelem a operačním systémem.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_24-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_25\" data-answer=\"d\">\n        <div class=\"question-label\">25. Nová cesta (nova_cesta) do proměnné PATH se přidá pomocí příkazu:</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_25\" value=\"a\" /><span><code>nova_cesta+PATH=$PATH</code></span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_25\" value=\"b\" /><span><code>ls $PATH:nova_cesta</code></span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_25\" value=\"c\" /><span><code>echo $PATH inova_cesta</code></span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_25\" value=\"d\" /><span><code>PATH=$PATH:nova_cesta</code></span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_25-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_26\" data-answer=\"c\">\n        <div class=\"question-label\">26. Ve firewallu iptables, který běží na koncové stanici – NE na směrovači, chceme změnit cílovou IP adresu. K tomuto účelu použijeme začátek které konstrukce?</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_26\" value=\"a\" /><span><code>sudo /sbin/iptables -t nat -A POSTROUTING</code></span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_26\" value=\"b\" /><span><code>sudo /sbin/iptables -t nat -A PREROUTING</code></span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_26\" value=\"c\" /><span><code>sudo /sbin/iptables -t nat -A OUTPUT</code></span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_26\" value=\"d\" /><span><code>sudo /sbin/iptables -t nat -A FORWARD</code></span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_26-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_27\" data-answer=\"c\">\n        <div class=\"question-label\">27. Vyberte pravdivé tvrzení o stínových heslech:</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_27\" value=\"a\" /><span>Při použití stínových hesel jsou hesla v zašifrované podobě uvedena v souboru /etc/passwd i /etc/shadow.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_27\" value=\"b\" /><span>Použití stínových hesel má výhodu v tom, že je uplatněn vyšší stupeň jejich šifrování...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_27\" value=\"c\" /><span>Soubor se stínovými hesly v zašifrované podobě může číst pouze root.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_27\" value=\"d\" /><span>Soubor se stínovými hesly v NEzašifrované podobě může číst pouze root.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_27-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_28\" data-answer=\"d\">\n        <div class=\"question-label\">28. Příkaz <code>cat < /etc/passwd > ~/hesla.txt</code> provede:</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_28\" value=\"a\" /><span>Přečte soubor hesla.txt v kořenovém adresáři...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_28\" value=\"b\" /><span>Přečte soubor hesla.txt v adresáři /home...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_28\" value=\"c\" /><span>Přečte hesla v souboru /etc/passwd...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_28\" value=\"d\" /><span>Přečte soubor s definicí uživatelů systému /etc/passwd a zapíše jej do souboru hesla.txt v domovském adresáři aktuálního uživatele.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_28-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_29\" data-answer=\"b\">\n        <div class=\"question-label\">29. Pokud chceme práva u souboru nastavit tak, aby spuštěný programový kód v souboru obsažený měl přístupová práva jako skupina vlastníka souboru, a dále právo spouštění souboru pouze pro vlastníka a skupinu vlastníka souboru; tak použijeme příkaz chmod s těmito parametry:</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_29\" value=\"a\" /><span>2001</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_29\" value=\"b\" /><span>2110</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_29\" value=\"c\" /><span>671</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_29\" value=\"d\" /><span>1661</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_29-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_30\" data-answer=\"a\">\n        <div class=\"question-label\">30. Pokud chceme práva u adresáře nastavit tak, aby soubory vytvořené v tomto adresáři získaly skupinové vlastnictví podle adresáře, a dále pro vlastníka adresáře plná práva; žádná práva pro skupinu vlastníka adresáře a ostatní uživatele, tak použijeme příkaz chmod s těmito parametry:</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_30\" value=\"a\" /><span>2700</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_30\" value=\"b\" /><span>700</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_30\" value=\"c\" /><span>0077</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_30\" value=\"d\" /><span>2007</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_30-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_31\" data-answer=\"d\">\n        <div class=\"question-label\">31. Při vytváření modulu jádra a jeho zavedení může dojít k poskvrnění jádra. Co je tím myšleno?</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_31\" value=\"a\" /><span>Zavedený modul jádra NEobsahoval povinný odkaz...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_31\" value=\"b\" /><span>Zavedený modul jádra používá i softwarově zakázané prostředky...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_31\" value=\"c\" /><span>Zavedený modul jádra NEbyl správně zkompilován...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_31\" value=\"d\" /><span>Zavedený modul jádra NEobsahoval formuli určující, že se jedná o software pod licencí GPL.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_31-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_32\" data-answer=\"b\">\n        <div class=\"question-label\">32. Na počítači byla nastavena statická IP adresa. Jakým příkazem by mohlo dojít k aktivaci nového nastavení?</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_32\" value=\"a\" /><span>rm -rfm</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_32\" value=\"b\" /><span>sudo /etc/init.d/network restart</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_32\" value=\"c\" /><span>sudo touch /etc/network</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_32\" value=\"d\" /><span>sudo vi /etc/network</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_32-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_33\" data-answer=\"b\">\n        <div class=\"question-label\">33. Vyberte funkční variantu zadání příkazu cat pro spojení obsahů souborů:</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_33\" value=\"a\" /><span><code>cat <vstup1.txt<vstup2.txt << vysledek.txt</code></span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_33\" value=\"b\" /><span><code>cat vstup1.txt vstup2.txt > vysledek.txt</code></span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_33\" value=\"c\" /><span><code>cat vstup1.txt|vstup2.txt >> vysledek.txt</code></span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_33\" value=\"d\" /><span><code>cat [vstup1.txt and vstup2.txt] to vysledek.txt</code></span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_33-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_34\" data-answer=\"b\">\n        <div class=\"question-label\">34. Jaký je výstup příkazu <code>echo $?</code>?</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_34\" value=\"a\" /><span>Vypíše všechny proměnné s hodnotou $...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_34\" value=\"b\" /><span>Vypíše návratový kód posledního spuštěného skriptu nebo příkazu.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_34\" value=\"c\" /><span>Vypíše návratový kód prvního spuštěného skriptu...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_34\" value=\"d\" /><span>Vypíše obsah všech proměnných.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_34-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_35\" data-answer=\"c\">\n        <div class=\"question-label\">35. Vyberte správnou vlastnost modulů jádra:</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_35\" value=\"a\" /><span>Po vložení do jádra NEní možné modul odebrat bez restartu...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_35\" value=\"b\" /><span>Typicky každý uživatel v systému... může vkládat moduly...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_35\" value=\"c\" /><span>Umožňují použití pouze těch funkcí jádra, které jsou v současné konfiguraci potřeba.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_35\" value=\"d\" /><span>Po vložení do jádra NEní možné modul používat bez restartu...</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_35-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_36\" data-answer=\"c\">\n        <div class=\"question-label\">36. Pokud chceme u adresáře nastavit pro vlastníka a skupinu vlastníka adresáře právo vstoupit a zobrazit soubory v adresáři; žádná práva pro ostatní uživatele, tak použijeme příkaz chmod s těmito parametry:</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_36\" value=\"a\" /><span>442</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_36\" value=\"b\" /><span>551</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_36\" value=\"c\" /><span>550</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_36\" value=\"d\" /><span>660</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_36-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_37\" data-answer=\"d\">\n        <div class=\"question-label\">37. Pokud chceme u souboru nastavit plná práva pro vlastníka souboru; právo čtení pro skupinu vlastníka souboru; právo spouštění pro ostatní uživatele, tak můžeme použít příkaz chmod s těmito parametry:</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_37\" value=\"a\" /><span>147</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_37\" value=\"b\" /><span>167</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_37\" value=\"c\" /><span>461</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_37\" value=\"d\" /><span>741</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_37-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_38\" data-answer=\"c\">\n        <div class=\"question-label\">38. Který z důvodů pro používání dynamických modulů jádra je NEpravdivý?</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_38\" value=\"a\" /><span>Dynamické moduly je možné přidávat do jádra za jeho běhu...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_38\" value=\"b\" /><span>Ovladače zařízení mohou být realizovány v podobě dynamického modulu.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_38\" value=\"c\" /><span>Dynamické moduly jsou nezbytné pro stabilní funkci jádra.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_38\" value=\"d\" /><span>Dynamické moduly umožňují rozšíření funkcí jádra.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_38-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_39\" data-answer=\"b\">\n        <div class=\"question-label\">39. Jaké vlastnictví získává soubor vytvořený v adresáři ve výchozím nastavení?</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_39\" value=\"a\" /><span>Soubor získává skupinové vlastnictví podle adresáře...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_39\" value=\"b\" /><span>Soubor získává vlastnictví podle uživatele, který jej vytvořil.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_39\" value=\"c\" /><span>Soubor získává vlastnictví podle způsobu vytvoření...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_39\" value=\"d\" /><span>Soubor získává vlastnictví podle uživatele, který vlastní adresář...</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_39-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_40\" data-answer=\"c\">\n        <div class=\"question-label\">40. Vyberte správné tvrzení o startu bezdiskové stanice po síti.</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_40\" value=\"a\" /><span>DHCP server předává bezdiskové stanici soubory s programy...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_40\" value=\"b\" /><span>Bezdiskové stanici musí být předán soubor s programem pro její restartování.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_40\" value=\"c\" /><span>DHCP server předává bezdiskové stanici název souboru se zavaděčem.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_40\" value=\"d\" /><span>Bezdisková stanice požádá v DHCP dotazu o heslo...</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_40-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_41\" data-answer=\"d\">\n        <div class=\"question-label\">41. Přítomnost příznaku setgid (s) v právech skupiny vlastníka souboru značí, že:</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_41\" value=\"a\" /><span>Pokud je soubor spuštěn, vzniklý proces má přístupová práva uživatele root.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_41\" value=\"b\" /><span>Pokud je soubor spuštěn, vzniklý proces má přístupová práva toho, kto soubor spustil.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_41\" value=\"c\" /><span>Pokud je soubor spuštěn, vzniklý proces má přístupová práva všech uživatelů...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_41\" value=\"d\" /><span>Pokud je soubor spuštěn, vzniklý proces má přístupová práva jako skupina vlastníka souboru.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_41-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_42\" data-answer=\"c\">\n        <div class=\"question-label\">42. Jakým způsobem pracuje slovníkový útok na hesla?</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_42\" value=\"a\" /><span>Daný uživatel je ze systému odhlášen...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_42\" value=\"b\" /><span>Ve slovníku jsou uložena zašifrovaná hesla v podobě otisku...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_42\" value=\"c\" /><span>Z NEzašifrovaného textu (jako možného hesla) ve slovníku je šifrovací funkcí vytvořen otisk a tento otisk je porovnán s otiskem uloženým v systému pro zadané heslo uživatele.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_42\" value=\"d\" /><span>Ve slovníku jsou uložena zašifrovaná hesla – otisky...</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_42-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_43\" data-answer=\"c\">\n        <div class=\"question-label\">43. Kterým příkazem změníme přístupová práva k adresáři?</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_43\" value=\"a\" /><span>ls</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_43\" value=\"b\" /><span>echo</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_43\" value=\"c\" /><span>chmod</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_43\" value=\"d\" /><span>sudo</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_43-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_44\" data-answer=\"d\">\n        <div class=\"question-label\">44. Řádek <code>147.229.147.10 kancelar01.utko.vutbr.cz</code> v souboru /etc/hosts značí následující:</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_44\" value=\"a\" /><span>IP adresa 147.229.147.10 bude zavedena do globálního systému DNS...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_44\" value=\"b\" /><span>IP adresa 147.229.147.10 je adresa místní stanice.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_44\" value=\"c\" /><span>Doménové jméno místní stanice je kancelar01.utko.vutbr.cz.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_44\" value=\"d\" /><span>Při komunikaci se stanicí kancelar01.utko.vutbr.cz bude použita IP adresa 147.229.147.10.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_44-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_45\" data-answer=\"c\">\n        <div class=\"question-label\">45. Uvažujme uživatelský účet se zadaným heslem. Uživatel zvolil dobré heslo. Máme přístup k otisku (hash) hesla. Jaký je nejlepší typ útoku?</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_45\" value=\"a\" /><span>Útok založený na porovnání uživatelského jména a hesla.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_45\" value=\"b\" /><span>Slovníkový útok...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_45\" value=\"c\" /><span>Útok hrubou silou, tj. testování kombinací všech možných znaků.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_45\" value=\"d\" /><span>Stažení běžných hesel dostupných na Internetu...</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_45-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_46\" data-answer=\"d\">\n        <div class=\"question-label\">46. Pokud chceme práva u adresáře nastavit tak, aby soubory vytvořené v tomto adresáři získaly skupinové vlastnictví podle adresáře, a dále pro vlastníka adresáře plná práva; žádná práva pro skupinu vlastníka adresáře a ostatní uživatele, tak použijeme příkaz chmod s těmito parametry:</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_46\" value=\"a\" /><span>0077</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_46\" value=\"b\" /><span>2007</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_46\" value=\"c\" /><span>700</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_46\" value=\"d\" /><span>2700</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_46-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_47\" data-answer=\"c\">\n        <div class=\"question-label\">47. Pomocí kterého základního příkazu nastavíme IP adresu a masku sítě?</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_47\" value=\"a\" /><span>route</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_47\" value=\"b\" /><span>ping</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_47\" value=\"c\" /><span>ifconfig nebo ip</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_47\" value=\"d\" /><span>traceroute</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_47-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_48\" data-answer=\"b\">\n        <div class=\"question-label\">48. Pokud chceme práva u souboru nastavit tak, aby spuštěný programový kód v souboru obsažený měl přístupová práva jako vlastník a skupina vlastníka souboru, a dále plná práva pro vlastníka souboru; pro skupinu vlastníka souboru a ostatní uživatele pouze právo spouštět, tak použijeme příkaz chmod s těmito parametry:</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_48\" value=\"a\" /><span>4744</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_48\" value=\"b\" /><span>6711</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_48\" value=\"c\" /><span>711</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_48\" value=\"d\" /><span>2477</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_48-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q1_49\" data-answer=\"d\">\n        <div class=\"question-label\">49. Vyberte správné tvrzení o digitálním podpisu:</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q1_49\" value=\"a\" /><span>Stejný pár veřejného a tajného klíče NElze zároveň použít...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_49\" value=\"b\" /><span>Pro digitální podpis si uživatel generuje tajný klíč...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_49\" value=\"c\" /><span>Uživatel A si může importovat veřejný uživatele B...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q1_49\" value=\"d\" /><span>Digitální podpis je NEplatný pokud změníme podepsaný text.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q1_49-fb\"></div>\n    </div>\n</div>\n\n<div class=\"section\" id=\"sec_2\" data-section=\"2\">\n    <div class=\"section-title\">2. BSOS 18/19L test (Úlohy a varianty)</div>\n\n    <div class=\"question\" id=\"q2_1\" data-answer=\"c\">\n        <div class=\"question-label\">1. Pomocí kterého základního příkazu nastavíme IP adresu a masku sítě?</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_1\" value=\"a\" /><span>route</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_1\" value=\"b\" /><span>ping</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_1\" value=\"c\" /><span>ifconfig nebo ip</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_1\" value=\"d\" /><span>traceroute</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_1-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_2\" data-answer=\"b\">\n        <div class=\"question-label\">2. Pokud chceme práva u souboru nastavit tak, aby spuštěný programový kód v souboru obsažený měl přístupová práva jako vlastník a skupina vlastníka souboru, a dále plná práva pro vlastníka souboru; pro skupinu vlastníka souboru a ostatní uživatele pouze právo spouštět, tak použijeme příkaz chmod s těmito parametry: (Úloha 1 B)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_2\" value=\"a\" /><span>4744</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_2\" value=\"b\" /><span>6711</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_2\" value=\"c\" /><span>711</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_2\" value=\"d\" /><span>2477</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_2-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_3\" data-answer=\"c\">\n        <div class=\"question-label\">3. Vyberte správnou vlastnost modulů jádra: (Úloha 1 C)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_3\" value=\"a\" /><span>Po vložení do jádra NEní možné modul odebrat bez restartu...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_3\" value=\"b\" /><span>Typicky každý uživatel... může vkládat moduly do jádra.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_3\" value=\"c\" /><span>Umožňují použití pouze těch funkcí jádra, které jsou v současné konfiguraci potřeba.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_3\" value=\"d\" /><span>Po vložení do jádra NEní možné modul používat bez restartu...</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_3-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_4\" data-answer=\"d\">\n        <div class=\"question-label\">4. Pokud chceme práva u souboru nastavit tak, aby spuštěný programový kód v souboru obsažený měl přístupová práva jako skupina vlastníka souboru, a dále právo spouštění souboru pouze pro vlastníka a skupinu vlastníka souboru; tak použijeme příkaz chmod s těmito parametry: (Úloha 1 D)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_4\" value=\"a\" /><span>1661</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_4\" value=\"b\" /><span>671</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_4\" value=\"c\" /><span>2001</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_4\" value=\"d\" /><span>2110</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_4-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_5\" data-answer=\"d\">\n        <div class=\"question-label\">5. Při vytváření modulu jádra a jeho zavedení může dojít k poskvrnění jádra. Co je tím myšleno? (Úloha 2)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_5\" value=\"a\" /><span>Zavedený modul jádra NEobsahoval povinný odkaz...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_5\" value=\"b\" /><span>Zavedený modul jádra používá i softwarově zakázané prostředky...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_5\" value=\"c\" /><span>Zavedený modul jádra NEbyl správně zkompilován...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_5\" value=\"d\" /><span>Zavedený modul jádra NEobsahoval formuli určující, že se jedná o software pod licencí GPL.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_5-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_6\" data-answer=\"c\">\n        <div class=\"question-label\">6. Výraz ve skriptu příkazového interpretu <code>#!/bin/bash</code> značí: (Úloha 2 B)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_6\" value=\"a\" /><span>Provedení příkazu /bin...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_6\" value=\"b\" /><span>Provedení příkazu /bin/bash na pozadí...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_6\" value=\"c\" /><span>Deklaraci programu, pomocí kterého se bude skript interpretovat.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_6\" value=\"d\" /><span>Provedení příkazu bash pod uživatelem root.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_6-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_7\" data-answer=\"a\">\n        <div class=\"question-label\">7. Jakým způsobem pracuje slovníkový útok na hesla? (Úloha 2 C)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_7\" value=\"a\" /><span>Z NEzašifrovaného textu (jako možného hesla) ve slovníku je šifrovací funkcí vytvořen otisk a tento otisk je porovnán s otiskem uloženým v systému...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_7\" value=\"b\" /><span>Daný uživatel je ze systému odhlášen...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_7\" value=\"c\" /><span>Ve slovníku jsou uložena zašifrovaná hesla v podobě otisků...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_7\" value=\"d\" /><span>Ve slovníku jsou uložena zašifrovaná hesla – otisky...</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_7-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_8\" data-answer=\"a\">\n        <div class=\"question-label\">8. K čemu je dobré zobrazení přehledu síťových spojení na síťovém zařízení? (Úloha 3)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_8\" value=\"a\" /><span>Pro získání přehledu otevřených portů a stavu jednotlivých spojení.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_8\" value=\"b\" /><span>Pro zjištění trasy ke vzdálené stanici...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_8\" value=\"c\" /><span>Pro zjištění verze operačních systému...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_8\" value=\"d\" /><span>Pro zjištění stavu směrovací tabulky...</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_8-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_9\" data-answer=\"c\">\n        <div class=\"question-label\">9. Uvažujme uživatelský účet se zadaným heslem. Uživatel zvolil dobré heslo. Máme přístup k otisku (hash) hesla. Jaký je nejlepší typ útoku? (Úloha 3 B)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_9\" value=\"a\" /><span>Útok založený na porovnání uživatelského jména a hesla.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_9\" value=\"b\" /><span>Slovníkový útok...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_9\" value=\"c\" /><span>Útok hrubou silou, tj. testování kombinací všech možných znaků.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_9\" value=\"d\" /><span>Stažení běžných hesel dostupných na Internetu...</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_9-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_10\" data-answer=\"d\">\n        <div class=\"question-label\">10. Jakým způsobem se spouští skript v příkazovém interpretu? (Úloha 3 C)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_10\" value=\"a\" /><span>Pomocí kompilace do binárního kódu pomocí příkazu gcc.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_10\" value=\"b\" /><span>Pomocí vytvoření symbolického odkazu...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_10\" value=\"c\" /><span>Pomocí vytvoření pevného odkazu...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_10\" value=\"d\" /><span>Pomocí příkazu <code>sh <název skriptu></code> nebo <code>./<název skriptu></code>.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_10-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_11\" data-answer=\"c\">\n        <div class=\"question-label\">11. Co je to příkazový interpret (shell)? (Úloha 3 D)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_11\" value=\"a\" /><span>Hardware, který je připojen k datové sběrnici...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_11\" value=\"b\" /><span>Program, který je součástí jádra operačního systému...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_11\" value=\"c\" /><span>Program, který NEní součástí jádra operačního systému. Je to prostředník mezi uživatelem a operačním systémem.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_11\" value=\"d\" /><span>Hardware, který slouží pro ovládání počítače hlasem.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_11-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_12\" data-answer=\"d\">\n        <div class=\"question-label\">12. Řádek <code>147.229.147.10 kancelar01.utko.vutbr.cz</code> v souboru /etc/hosts značí následující: (Úloha 4)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_12\" value=\"a\" /><span>IP adresa 147.229.147.10 bude zavedena do globálního systému DNS...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_12\" value=\"b\" /><span>IP adresa 147.229.147.10 je adresa místní stanice.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_12\" value=\"c\" /><span>Doménové jméno místní stanice je kancelar01.utko.vutbr.cz.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_12\" value=\"d\" /><span>Při komunikaci se stanicí kancelar01.utko.vutbr.cz bude použita IP adresa 147.229.147.10.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_12-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_13\" data-answer=\"c\">\n        <div class=\"question-label\">13. Jaké jsou důležité programy pro zobrazení konfigurace sítě? (Úloha 4 B)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_13\" value=\"a\" /><span>bash a sudo</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_13\" value=\"b\" /><span>config a chmod</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_13\" value=\"c\" /><span>ifconfig a ip</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_13\" value=\"d\" /><span>chmod a touch</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_13-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_14\" data-answer=\"d\">\n        <div class=\"question-label\">14. Pokud chceme u souboru nastavit plná práva pro vlastníka souboru; právo čtení pro skupinu vlastníka souboru; právo spouštění pro ostatní uživatele, tak můžeme použít příkaz chmod s těmito parametry: (Úloha 4 C)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_14\" value=\"a\" /><span>147</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_14\" value=\"b\" /><span>167</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_14\" value=\"c\" /><span>461</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_14\" value=\"d\" /><span>741</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_14-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_15\" data-answer=\"a\">\n        <div class=\"question-label\">15. Jaký efekt bude mít sekvence příkazů <code>more hesla.txt; who am i; echo $PATH</code>? (Úloha 5)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_15\" value=\"a\" /><span>Příkazy budou provedeny postupně zleva doprava: nejdříve se provede výpis obsahu souboru hesla.txt, pak výpis informací o aktuálním uživateli, nakonec výpis systémové proměnné PATH.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_15\" value=\"b\" /><span>První dva příkazy budou spuštěny najednou...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_15\" value=\"c\" /><span>Příkazy budou zřetězeny...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_15\" value=\"d\" /><span>Příkazy budou provedeny postupně zprava doleva.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_15-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_16\" data-answer=\"b\">\n        <div class=\"question-label\">16. Jaké informace značí výpis <code>lrwxrwxrwx</code> u položky ve výpisu obsahu adresáře? (Úloha 5 B)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_16\" value=\"a\" /><span>Nastala chyba v souborovém systému.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_16\" value=\"b\" /><span>Práva jsou ignorována.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_16\" value=\"c\" /><span>Právo čtení, zápisu a spouštění má vlastník...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_16\" value=\"d\" /><span>Jedná se o adresář uživatele root.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_16-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_17\" data-answer=\"c\">\n        <div class=\"question-label\">17. U adresáře je uvedeno oprávnění označené jako x. Co toto oprávnění značí? (Úloha 5 C)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_17\" value=\"a\" /><span>Oprávnění k přesunu.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_17\" value=\"b\" /><span>Oprávnění ke spuštění.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_17\" value=\"c\" /><span>Oprávnění ke vstupu.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_17\" value=\"d\" /><span>Oprávnění k mazání.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_17-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_18\" data-answer=\"b\">\n        <div class=\"question-label\">18. Jaké vlastnictví získává soubor vytvořený v adresáři ve výchozím nastavení? (Úloha 5 D)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_18\" value=\"a\" /><span>Soubor získává skupinové vlastnictví podle adresáře...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_18\" value=\"b\" /><span>Soubor získává vlastnictví podle uživatele, který jej vytvořil.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_18\" value=\"c\" /><span>Soubor získává vlastnictví podle způsobu vytvoření...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_18\" value=\"d\" /><span>Soubor získává vlastnictví podle uživatele, který vlastní adresář...</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_18-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_19\" data-answer=\"c\">\n        <div class=\"question-label\">19. Ve firewallu iptables, který běží na koncové stanici – NE na směrovači, chceme změnit cílovou IP adresu. K tomuto účelu použijeme začátek které konstrukce? (Úloha 6)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_19\" value=\"a\" /><span><code>sudo /sbin/iptables -t nat -A POSTROUTING</code></span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_19\" value=\"b\" /><span><code>sudo /sbin/iptables -t nat -A PREROUTING</code></span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_19\" value=\"c\" /><span><code>sudo /sbin/iptables -t nat -A OUTPUT</code></span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_19\" value=\"d\" /><span><code>sudo /sbin/iptables -t nat -A FORWARD</code></span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_19-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_20\" data-answer=\"b\">\n        <div class=\"question-label\">20. Jaký je výstup příkazu <code>echo $?</code>? (Úloha 6 B)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_20\" value=\"a\" /><span>Vypíše všechny proměnné s hodnotou $...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_20\" value=\"b\" /><span>Vypíše návratový kód posledního spuštěného skriptu nebo příkazu.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_20\" value=\"c\" /><span>Vypíše návratový kód prvního spuštěného skriptu...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_20\" value=\"d\" /><span>Vypíše obsah všech proměnných.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_20-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_21\" data-answer=\"d\">\n        <div class=\"question-label\">21. Jakým způsobem se spouští skript v příkazovém interpretu? (Úloha 6 C)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_21\" value=\"a\" /><span>Pomocí vytvoření symbolického odkazu...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_21\" value=\"b\" /><span>Pomocí vytvoření pevného odkazu...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_21\" value=\"c\" /><span>Pomocí kompilace do binárního kódu pomocí příkazu gcc.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_21\" value=\"d\" /><span>Pomocí příkazu <code>sh <název skriptu></code> nebo <code>./<název skriptu></code>.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_21-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_22\" data-answer=\"c\">\n        <div class=\"question-label\">22. Který z důvodů pro používání dynamických modulů jádra je NEpravdivý? (Úloha 6 D)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_22\" value=\"a\" /><span>Dynamické moduly je možné přidávat do jádra za jeho běhu...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_22\" value=\"b\" /><span>Ovladače zařízení mohou být realizovány v podobě dynamického modulu.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_22\" value=\"c\" /><span>Dynamické moduly jsou nezbytné pro stabilní funkci jádra.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_22\" value=\"d\" /><span>Dynamické moduly umožňují rozšíření funkcí jádra.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_22-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_23\" data-answer=\"c\">\n        <div class=\"question-label\">23. Příkazy <code>cd /home/uzivatel/temp/; ./skript.sh</code> spustí skript.sh: (Úloha 7)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_23\" value=\"a\" /><span>Z adresáře /home</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_23\" value=\"b\" /><span>Z adresáře /bin</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_23\" value=\"c\" /><span>Z aktuálního adresáře.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_23\" value=\"d\" /><span>Z adresáře /root</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_23-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_24\" data-answer=\"c\">\n        <div class=\"question-label\">24. Určete, které použití znaku roury a znaků přesměrování je správné k tomu, abychom vypsali obsah souboru /data/seznam tak, aby byly vypsány pouze řádky s výskytem slova root. (Úloha 7 B)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_24\" value=\"a\" /><span><code>cat | grep | sort </data/seznam root > /data/serazeno</code></span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_24\" value=\"b\" /><span><code>sort | grep | sort </data/serazeno >/data/seznam root</code></span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_24\" value=\"c\" /><span><code>cat /data/seznam | grep root | sort >/data/serazeno</code></span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_24\" value=\"d\" /><span><code>cat | grep | sort </data/serazeno root >/data/seznam</code></span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_24-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_25\" data-answer=\"d\">\n        <div class=\"question-label\">25. Pokud chceme práva u adresáře nastavit tak, aby soubory vytvořené v tomto adresáři získaly skupinové vlastnictví podle adresáře, a dále pro vlastníka adresáře plná práva; žádná práva pro skupinu vlastníka adresáře a ostatní uživatele, tak použijeme příkaz chmod s těmito parametry: (Úloha 7 C)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_25\" value=\"a\" /><span>0077</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_25\" value=\"b\" /><span>2007</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_25\" value=\"c\" /><span>700</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_25\" value=\"d\" /><span>2700</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_25-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_26\" data-answer=\"d\">\n        <div class=\"question-label\">26. Nová cesta (nova_cesta) do proměnné PATH se přidá pomocí příkazu: (Úloha 8)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_26\" value=\"a\" /><span><code>nova_cesta+PATH=$PATH</code></span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_26\" value=\"b\" /><span><code>ls $PATH:nova_cesta</code></span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_26\" value=\"c\" /><span><code>echo $PATH:nova_cesta</code></span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_26\" value=\"d\" /><span><code>PATH=$PATH:nova_cesta</code></span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_26-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_27\" data-answer=\"d\">\n        <div class=\"question-label\">27. Přítomnost příznaku setgid (s) v právech skupiny vlastníka souboru značí, že: (Úloha 8 B)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_27\" value=\"a\" /><span>Pokud je soubor spuštěn, vzniklý proces má přístupová práva uživatele root.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_27\" value=\"b\" /><span>Pokud je soubor spuštěn, vzniklý proces má přístupová práva toho, kto soubor spustil.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_27\" value=\"c\" /><span>Pokud je soubor spuštěn, vzniklý proces má přístupová práva všech uživatelů...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_27\" value=\"d\" /><span>Pokud je soubor spuštěn, vzniklý proces má přístupová práva jako skupina vlastníka souboru.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_27-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_28\" data-answer=\"a\">\n        <div class=\"question-label\">28. Pokud chceme práva u adresáře nastavit tak, aby soubory vytvořené v tomto adresáři získaly skupinové vlastnictví podle adresáře, a dále pro vlastníka adresáře plná práva; žádná práva pro skupinu vlastníka adresáře a ostatní uživatele, tak použijeme příkaz chmod s těmito parametry: (Úloha 8 C)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_28\" value=\"a\" /><span>2700</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_28\" value=\"b\" /><span>700</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_28\" value=\"c\" /><span>0077</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_28\" value=\"d\" /><span>2007</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_28-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_29\" data-answer=\"a\">\n        <div class=\"question-label\">29. Ve cvičení jste si příkazem gpg pro účely bezpečné komunikace generovali: (Úloha 8 D)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_29\" value=\"a\" /><span>Veřejný a privátní klíč.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_29\" value=\"b\" /><span>Pouze tajný klíč.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_29\" value=\"c\" /><span>Symetrický klíč.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_29\" value=\"d\" /><span>Pouze veřejný klíč.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_29-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_30\" data-answer=\"c\">\n        <div class=\"question-label\">30. Vyberte pravdivé tvrzení o stínových heslech: (Úloha 9)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_30\" value=\"a\" /><span>Při použití stínových hesel jsou hesla v zašifrované podobě uvedena v souboru /etc/passwd i /etc/shadow.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_30\" value=\"b\" /><span>Použití stínových hesel má výhodu v tom, že je uplatněn vyšší stupeň jejich šifrování...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_30\" value=\"c\" /><span>Soubor se stínovými hesly v zašifrované podobě může číst pouze root.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_30\" value=\"d\" /><span>Soubor se stínovými hesly v NEzašifrované podobě může číst pouze root.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_30-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_31\" data-answer=\"a\">\n        <div class=\"question-label\">31. Co značí u nastavení oprávnění souboru hodnota 664? (Úloha 9 B)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_31\" value=\"a\" /><span>Všichni uživatelé mohou soubor číst, vlastník souboru a skupina vlastníka souboru mohou do souboru zapisovat.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_31\" value=\"b\" /><span>Vlastník souboru a skupina vlastníka souboru může soubor spustit...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_31\" value=\"c\" /><span>Vlastník souboru a skupina vlastníka souboru může soubor spustit...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_31\" value=\"d\" /><span>Všichni uživatelé mohou soubor číst, vlastník souboru a skupina vlastníka souboru může soubor spustit.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_31-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_32\" data-answer=\"a\">\n        <div class=\"question-label\">32. Administrátor systému se rozhodl přejít na použití stínových hesel v souboru /etc/shadow. Vyberte správnou akci pro zavedení souboru. (Úloha 9 C)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_32\" value=\"a\" /><span>chmod 400 /etc/shadow</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_32\" value=\"b\" /><span>chmod 004 /etc/shadow</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_32\" value=\"c\" /><span>chmod 444 /etc/shadow</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_32\" value=\"d\" /><span>chmod 006 /etc/shadow</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_32-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_33\" data-answer=\"d\">\n        <div class=\"question-label\">33. V jakých sítích je vhodné použití programu Telnet? (Úloha 9 D)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_33\" value=\"a\" /><span>Pro svou grafickou náročnost...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_33\" value=\"b\" /><span>Pro svou jednoduchost... ve veřejné síti Internet.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_33\" value=\"c\" /><span>Pro svou jednoduchost... ve starších sítích...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_33\" value=\"d\" /><span>Pouze v privátních sítích (např. laboratoř), bez napojení na vnější síť.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_33-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_34\" data-answer=\"a\">\n        <div class=\"question-label\">34. Jak je možné zajistit neprivilegovanému uživateli možnost spouštět určité příkazy s právy administrátora (root)? (Úloha 10)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_34\" value=\"a\" /><span>Lze použít nástroj sudo ve formátu: sudo příkaz. V souboru /etc/sudoers jsou pak uloženy příkazy...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_34\" value=\"b\" /><span>Vytvořením symbolického odkazu...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_34\" value=\"c\" /><span>Vytvořením pevného odkazu...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_34\" value=\"d\" /><span>Pomocí zamezení používání stínových hesel...</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_34-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_35\" data-answer=\"b\">\n        <div class=\"question-label\">35. Aktuální adresář se do proměnné PATH nezahrnuje z důvodu: (Úloha 10 B)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_35\" value=\"a\" /><span>Spustitelné soubory z aktuálního adresáře se spouštějí automaticky...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_35\" value=\"b\" /><span>Bezpečnosti.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_35\" value=\"c\" /><span>Spustitelné soubory nebývají umístěny mimo adresář /bin.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_35\" value=\"d\" /><span>V proměnné PATH může být jenom adresář /bin.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_35-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_36\" data-answer=\"b\">\n        <div class=\"question-label\">36. Na počítači byla nastavena statická IP adresa. Jakým příkazem by mohlo dojít k aktivaci nového nastavení? (Úloha 10 C)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_36\" value=\"a\" /><span>rm -rf ~</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_36\" value=\"b\" /><span>sudo /etc/init.d/network restart</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_36\" value=\"c\" /><span>sudo touch /etc/network</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_36\" value=\"d\" /><span>sudo vi /etc/network</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_36-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_37\" data-answer=\"c\">\n        <div class=\"question-label\">37. Pokud chceme u adresáře nastavit pro vlastníka a skupinu vlastníka adresáře právo vstoupit a zobrazit soubory v adresáři; žádná práva pro ostatní uživatele, tak použijeme příkaz chmod s těmito parametry: (Úloha 11)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_37\" value=\"a\" /><span>442</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_37\" value=\"b\" /><span>551</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_37\" value=\"c\" /><span>550</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_37\" value=\"d\" /><span>660</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_37-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_38\" data-answer=\"d\">\n        <div class=\"question-label\">38. V jakých sítích je vhodné použití programu Telnet? (Úloha 11 B)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_38\" value=\"a\" /><span>Pro svou grafickou náročnost...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_38\" value=\"b\" /><span>Pro svou jednoduchost... ve starších sítích...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_38\" value=\"c\" /><span>Pro svou jednoduchost... ve veřejné síti Internet.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_38\" value=\"d\" /><span>Pouze v privátních sítích (např. laboratoř), bez napojení na vnější síť.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_38-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_39\" data-answer=\"b\">\n        <div class=\"question-label\">39. Kterým příkazem změníme přístupová práva k adresáři? (Úloha 11 C)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_39\" value=\"a\" /><span>ls</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_39\" value=\"b\" /><span>chmod</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_39\" value=\"c\" /><span>sudo</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_39\" value=\"d\" /><span>echo</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_39-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_40\" data-answer=\"a\">\n        <div class=\"question-label\">40. Pokud chceme u adresáře nastavit pro vlastníka a skupinu vlastníka adresáře právo vstoupit a zobrazit soubory v adresáři; žádná práva pro ostatní uživatele, tak použijeme příkaz chmod s těmito parametry: (Úloha 12)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_40\" value=\"a\" /><span>550</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_40\" value=\"b\" /><span>660</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_40\" value=\"c\" /><span>442</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_40\" value=\"d\" /><span>551</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_40-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_41\" data-answer=\"a\">\n        <div class=\"question-label\">41. Aktuální adresář se do proměnné PATH nezahrnuje z důvodu: (Úloha 12 B)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_41\" value=\"a\" /><span>Bezpečnosti.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_41\" value=\"b\" /><span>Spustitelné soubory nebývají umístěny mimo adresář /bin.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_41\" value=\"c\" /><span>V proměnné PATH může být jenom adresář /bin.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_41\" value=\"d\" /><span>Spustitelné soubory z aktuálního adresáře se spouštějí automaticky...</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_41-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_42\" data-answer=\"b\">\n        <div class=\"question-label\">42. Vyberte funkční variantu zadání příkazu cat pro spojení obsahů souborů: (Úloha 12 C)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_42\" value=\"a\" /><span><code>cat < vstup1.txt < vstup2.txt << vysledek.txt</code></span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_42\" value=\"b\" /><span><code>cat vstup1.txt vstup2.txt > vysledek.txt</code></span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_42\" value=\"c\" /><span><code>cat vstup1.txt | vstup2.txt >> vysledek.txt</code></span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_42\" value=\"d\" /><span><code>cat [vstup1.txt and vstup2.txt] to vysledek.txt</code></span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_42-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_43\" data-answer=\"d\">\n        <div class=\"question-label\">43. Příkaz <code>cat < /etc/passwd > ~/hesla.txt</code> provede: (Úloha 13)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_43\" value=\"a\" /><span>Přečte soubor hesla.txt v kořenovém adresáři...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_43\" value=\"b\" /><span>Přečte soubor hesla.txt v adresáři /home...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_43\" value=\"c\" /><span>Přečte hesla v souboru /etc/passwd...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_43\" value=\"d\" /><span>Přečte soubor s definicí uživatelů systému /etc/passwd a zapíše jej do souboru hesla.txt v domovském adresáři aktuálního uživatele.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_43-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_44\" data-answer=\"b\">\n        <div class=\"question-label\">44. Co můžete říci o těchto dvou různých zápisech IP adresy z pohledu masky sítě? 1) 192.168.1.0 255.255.255.0; 2) 192.168.1.0/24 (Úloha 13 B)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_44\" value=\"a\" /><span>Oba dva zápisy jsou chybné.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_44\" value=\"b\" /><span>Uvedená maska sítě je v obou případech stejná.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_44\" value=\"c\" /><span>Případ 2) NEvyjadřuje zápis IP adresy...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_44\" value=\"d\" /><span>Případ 1) NEvyjadřuje správný zápis IP adresy...</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_44-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_45\" data-answer=\"d\">\n        <div class=\"question-label\">45. Vyberte správné tvrzení o digitálním podpisu: (Úloha 13 C)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_45\" value=\"a\" /><span>Stejný pár veřejného a tajného klíče NElze zároveň použít...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_45\" value=\"b\" /><span>Pro digitální podpis si uživatel generuje tajný klíč...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_45\" value=\"c\" /><span>Uživatel A si může importovat veřejný uživatele B...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_45\" value=\"d\" /><span>Digitální podpis je NEplatný pokud změníme podepsaný text.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_45-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_46\" data-answer=\"a\">\n        <div class=\"question-label\">46. Co bude provádět konstrukce <code>***** ~/copy.sh >> ~/zaloha.txt</code>, kterou předáte programu crontab? (Úloha 14)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_46\" value=\"a\" /><span>Do souboru zaloha.txt se bude přidávat textový výstup skriptu copy.sh.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_46\" value=\"b\" /><span>Skript copy.sh se bude spouštět jednou za rok.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_46\" value=\"c\" /><span>Obsah skriptu copy.sh bude každou minutu zkopírován...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_46\" value=\"d\" /><span>Program crontab NEbude provádět nic...</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_46-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_47\" data-answer=\"c\">\n        <div class=\"question-label\">47. U souboru máme nastaveno toto oprávnění, vlastník: rwx, skupina: rw-, ostatní: r-. Jaká bude číselná hodnota tohoto oprávnění? (Úloha 14 B)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_47\" value=\"a\" /><span>676</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_47\" value=\"b\" /><span>670</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_47\" value=\"c\" /><span>764</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_47\" value=\"d\" /><span>766</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_47-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_48\" data-answer=\"c\">\n        <div class=\"question-label\">48. Vyberte správné tvrzení o startu bezdiskové stanice po síti. (Úloha 14 C)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_48\" value=\"a\" /><span>DHCP server předává bezdiskové stanici soubory s programy...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_48\" value=\"b\" /><span>Bezdiskové stanici musí být předán soubor s programem...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_48\" value=\"c\" /><span>DHCP server předává bezdiskové stanici název souboru se zavaděčem.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_48\" value=\"d\" /><span>Bezdisková stanice požádá v DHCP dotazu o heslo...</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_48-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_49\" data-answer=\"a\">\n        <div class=\"question-label\">49. Jaké informace značí výpis <code>lrwxrwxrwx</code> u položky ve výpisu obsahu adresáře? (Úloha 15)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_49\" value=\"a\" /><span>Pouze to, že se jedná o symbolický odkaz.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_49\" value=\"b\" /><span>Pouze to, že se jedná o adresář.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_49\" value=\"c\" /><span>Vlastníkem položky s těmito právy je uživatel root.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_49\" value=\"d\" /><span>Vlastníkem položky s těmito právy je aktuální uživatel.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_49-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_50\" data-answer=\"b\">\n        <div class=\"question-label\">50. Pokud chceme práva u souboru nastavit tak, aby spuštěný programový kód v souboru obsažený měl přístupová práva jako skupina vlastníka souboru... (Úloha 15 B)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_50\" value=\"a\" /><span>2001</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_50\" value=\"b\" /><span>2110</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_50\" value=\"c\" /><span>671</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_50\" value=\"d\" /><span>1661</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_50-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_51\" data-answer=\"d\">\n        <div class=\"question-label\">51. Hlášení \"module licence XY taints kernel\" v systémovém logu může znamenat, že: (Úloha 15 C)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_51\" value=\"a\" /><span>Do jádra byl vložen modul s neoriginálním ovladačem.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_51\" value=\"b\" /><span>Nastala chyba v modulu jádra...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_51\" value=\"c\" /><span>Jádro bylo infikováno virem nebo malwarem s licencí.</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_51\" value=\"d\" /><span>Do jádra byl zaveden modul bez zadané licence.</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_51-fb\"></div>\n    </div>\n\n    <div class=\"question\" id=\"q2_52\" data-answer=\"a\">\n        <div class=\"question-label\">52. Jakým způsobem pracuje slovníkový útok na hesla? (Úloha 15 D)</div>\n        <div class=\"options\">\n            <label class=\"option\"><input type=\"radio\" name=\"q2_52\" value=\"a\" /><span>Z NEzašifrovaného textu (jako možného hesla) ve slovníku je šifrovací funkcí vytvořen otisk...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_52\" value=\"b\" /><span>Daný uživatel je ze systému odhlášen...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_52\" value=\"c\" /><span>Ve slovníku jsou uložena zašifrovaná hesla v podobě otisků...</span></label>\n            <label class=\"option\"><input type=\"radio\" name=\"q2_52\" value=\"d\" /><span>Ve slovníku jsou uložena zašifrovaná hesla – otisky...</span></label>\n        </div>\n        <div class=\"feedback\" id=\"q2_52-fb\"></div>\n    </div>\n</div>\n";
